import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

public class JsonWriter_value_Test {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_writesLongValue_correctly() throws IOException {
    // We rely on default state: stack is empty, no deferredName
    jsonWriter.value(123456789L);
    assertEquals("123456789", stringWriter.toString());
  }

  @Test
  public void value_writesLongValue_withDeferredName_andStackState() throws Exception {
    // Use reflection to set private fields deferredName and stack/stackSize to simulate state
    // Set deferredName to a string so writeDeferredName() writes it
    var deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(jsonWriter, "foo");

    // Set stack and stackSize to simulate state so beforeValue() behaves differently
    var stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    var stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 0; // arbitrary valid state
    var stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);

    // We also need to set indent and separator to test beforeValue() branches
    var indentField = JsonWriter.class.getDeclaredField("indent");
    indentField.setAccessible(true);
    indentField.set(jsonWriter, "  ");
    var separatorField = JsonWriter.class.getDeclaredField("separator");
    separatorField.setAccessible(true);
    separatorField.set(jsonWriter, " : ");

    // Call value(long)
    jsonWriter.value(42L);

    // The output should contain the deferredName and the long value
    String output = stringWriter.toString();
    assertTrue(output.contains("foo"));
    assertTrue(output.contains("42"));
  }

  @Test
  public void value_invokesWriteDeferredName_andBeforeValue() throws Exception {
    // Spy on JsonWriter to verify private methods called via reflection
    JsonWriter spyWriter = spy(new JsonWriter(new StringWriter()));

    // Use reflection to invoke value(long)
    Method valueMethod = JsonWriter.class.getDeclaredMethod("value", long.class);
    valueMethod.setAccessible(true);

    valueMethod.invoke(spyWriter, 7L);

    // Verify writeDeferredName() and beforeValue() called once each
    verify(spyWriter, times(1)).writeDeferredName();
    verify(spyWriter, times(1)).beforeValue();
  }
}

